import { Hono } from 'hono';
import { cors } from 'hono/cors';
import { logger } from 'hono/logger';
import { drizzle } from 'drizzle-orm/d1';
import * as schema from './db/schema';

// Import routes
import { authRoutes } from './routes/auth';
import { leagueRoutes } from './routes/leagues';
import { teamRoutes } from './routes/teams';
import { playerRoutes } from './routes/players';
import { matchupRoutes } from './routes/matchups';
import { gameRoutes } from './routes/games';
import { adminRoutes } from './routes/admin';
import { feedbackRoutes } from './routes/feedback';

// Types
export type Env = {
  DB: D1Database;
  JWT_SECRET: string;
  ENVIRONMENT: string;
  SYNC_SECRET?: string; // Optional: required for POST /api/admin/sync-players
  TWITTER_RSS_URLS?: string; // Comma-separated RSS URLs, e.g. https://nitter.net/AdamSchefter/rss
  OPENAI_API_KEY?: string; // For AI relevance filtering of player news
};

export type Variables = {
  db: ReturnType<typeof drizzle<typeof schema>>;
  user?: schema.User;
};

// Create app
const app = new Hono<{ Bindings: Env; Variables: Variables }>();

// Global middleware
app.use('*', logger());
const allowedOrigins = [
  'http://localhost:3000', 'http://localhost:3001', 'http://localhost:5173',
  'http://127.0.0.1:3000', 'http://127.0.0.1:3001', 'http://127.0.0.1:5173',
];
app.use('*', cors({
  origin: (origin) => {
    if (!origin) return allowedOrigins[0];
    if (allowedOrigins.includes(origin)) return origin;
    if (origin.endsWith('.pages.dev') || origin.endsWith('.cloudflarepages.com')) return origin;
    return allowedOrigins[0];
  },
  allowMethods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
  allowHeaders: ['Content-Type', 'Authorization'],
  credentials: true,
}));

// Database middleware - attach drizzle instance to context
app.use('*', async (c, next) => {
  const db = drizzle(c.env.DB, { schema });
  c.set('db', db);
  await next();
});

// Health check
app.get('/', (c) => {
  return c.json({
    status: 'ok',
    name: 'FilmRoom Fantasy API',
    version: '1.0.0',
    environment: c.env.ENVIRONMENT,
  });
});

app.get('/health', (c) => {
  return c.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

// Mount routes
app.route('/api/auth', authRoutes);
app.route('/api/leagues', leagueRoutes);
app.route('/api/teams', teamRoutes);
app.route('/api/players', playerRoutes);
app.route('/api/matchups', matchupRoutes);
app.route('/api/games', gameRoutes);
app.route('/api/admin', adminRoutes);
app.route('/api/feedback', feedbackRoutes);

// 404 handler
app.notFound((c) => {
  return c.json({ error: 'Not found', path: c.req.path }, 404);
});

// Error handler
app.onError((err, c) => {
  return c.json({
    error: 'Internal server error',
    message: c.env.ENVIRONMENT === 'development' ? err.message : undefined,
  }, 500);
});

export default app;
